sql:
SELECT SUM(volume) AS total_volume
FROM commodity_prices
WHERE commodity_id = 1;

SELECT commodity_id, price
FROM commodity_prices
WHERE currency = 'USD';

SELECT commodity_id, AVG(price) AS average_price
FROM commodity_prices
GROUP BY commodity_id;

SELECT DISTINCT u.username
FROM users u
WHERE EXISTS (
    SELECT 1 FROM alerts a WHERE a.user_id = u.user_id
) AND EXISTS (
    SELECT 1 FROM reports r WHERE r.user_id = u.user_id
);

SELECT commodity_id, price
FROM commodity_prices
WHERE price < 130.0 AND currency = 'USD';

SELECT price 
FROM price_histories 
WHERE history_id = 0;

external_knowledge:
- 'crown jewels' refers to the commodities with the highest average price; 
- 'world of commodity trading' refers to the domain of the query; 
- 'watchful eye' refers to an active alert.

